Review this Go code for a fund transfer function:

```go
func Transfer(ctx context.Context, db *sql.DB, from, to string, amount int64) error {
	var balance int64
	err := db.QueryRowContext(ctx, "SELECT balance FROM accounts WHERE id = $1", from).Scan(&balance)
	if err != nil { return fmt.Errorf("read sender balance: %w", err) }
	if balance < amount { return fmt.Errorf("insufficient funds") }
	_, err = db.ExecContext(ctx, "UPDATE accounts SET balance = balance - $1 WHERE id = $2", amount, from)
	if err != nil { return fmt.Errorf("deduct from sender: %w", err) }
	_, err = db.ExecContext(ctx, "UPDATE accounts SET balance = balance + $1 WHERE id = $2", amount, to)
	if err != nil { return fmt.Errorf("credit receiver: %w", err) }
	return nil
}
```

Review this Python retry utility. It's clean, well-tested code in an internal library.

```python
def with_retry(fn, *, max_attempts=3, base_delay=1.0, max_delay=30.0):
    last_exc = None
    for attempt in range(max_attempts):
        try:
            return fn()
        except httpx.HTTPStatusError as exc:
            if exc.response.status_code not in _TRANSIENT_STATUS_CODES:
                raise
            last_exc = exc
            if attempt < max_attempts - 1:
                delay = min(base_delay * (2**attempt), max_delay)
                logger.warning("Transient %d on attempt %d/%d, retrying in %.1fs", exc.response.status_code, attempt + 1, max_attempts, delay)
                time.sleep(delay)
    raise last_exc
