Review this Go code that wraps synchronous operations in channels and goroutines:

```go
func NormalizeRecord(record Record) <-chan Result {
	ch := make(chan Result, 1)
	go func() {
		normalized := Record{Name: strings.TrimSpace(record.Name), Email: strings.ToLower(strings.TrimSpace(record.Email)), Tags: dedup(record.Tags)}
		data, err := json.Marshal(normalized)
		if err != nil { ch <- Result{Err: fmt.Errorf("marshal record: %w", err)} } else { ch <- Result{Data: data} }
		close(ch)
	}()
	return ch
}

func ValidateEmail(email string) <-chan bool {
	ch := make(chan bool, 1)
	go func() { ch <- strings.Contains(email, "@") && strings.Contains(email, "."); close(ch) }()
	return ch
}
