async function buildPackage(packageName, outputDir) {
  if (fs.existsSync(outputDir)) {
    const stats = fs.statSync(outputDir);
    if (!stats.isDirectory()) throw new Error('Output path is not a directory');
  } else {
    fs.mkdirSync(outputDir, { recursive: true });
  }
  const buildCmd = `npm pack ${packageName} --pack-destination ${outputDir}`;
  return new Promise((resolve, reject) => {
    exec(buildCmd, (error, stdout) => {
      if (error) { reject(error); return; }
      resolve(stdout.trim());
    });
  });
}
