func (h *ListHandler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}
	cursor := r.URL.Query().Get("cursor")
	limit := 20
	items, nextCursor, err := h.store.List(r.Context(), cursor, limit)
	if err != nil {
		h.log.ErrorContext(r.Context(), "list items failed", "error", err, "cursor", cursor)
		if errors.Is(err, context.Canceled) { return }
		http.Error(w, "internal error", http.StatusInternalServerError)
		return
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]any{"items": items, "next_cursor": nextCursor})
}
